      const w = this.write;
      for (let c = 0; c < ch; c++) {
        const src = input ? (input[c] || input[0]) : null;
        this.rings[c][w] = src ? (src[i] || 0) : 0;
      }
      let p = this.phase + inc;
      p -= Math.floor(p); // wraps both directions (floor of negatives)
      this.phase = p;
      const p2 = (p + 0.5) % 1;
